1	export type Cell = [number, number];
2	
3	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
4	
5	const NEIGHBOR_OFFSETS: Cell[] = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const survivesToNextGeneration = (isAlive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (neighborCount === 2 && isAlive);
13	
14	const countLiveNeighbors = (liveCells: Cell[]): Map<string, { cell: Cell; count: number }> => {
15	  const counts = new Map<string, { cell: Cell; count: number }>();
16	  for (const [x, y] of liveCells) {
17	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
18	      const neighbor: Cell = [x + dx, y + dy];
19	      const k = cellKey(neighbor);
20	      const entry = counts.get(k);
21	      if (entry) entry.count += 1;
22	      else counts.set(k, { cell: neighbor, count: 1 });
23	    }
24	  }
25	  return counts;
26	};
27	
28	export function nextGeneration(liveCells: Cell[]): Cell[] {
29	  const aliveKeys = new Set(liveCells.map(cellKey));
30	  const neighborCounts = countLiveNeighbors(liveCells);
31	
32	  const nextLiveCells: Cell[] = [];
33	  for (const [k, { cell, count }] of neighborCounts) {
34	    if (survivesToNextGeneration(aliveKeys.has(k), count)) {
35	      nextLiveCells.push(cell);
36	    }
37	  }
38	  return nextLiveCells;
39	}
