4	describe("Game of Life - nextGeneration", () => {
5	  it("empty input returns empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("live cell with 2 neighbors survives (survival) — center of row [(0,1),(1,1),(2,1)] stays alive", () => {
21	    const row: Cell[] = [[0, 1], [1, 1], [2, 1]];
22	    const result = nextGeneration(row);
23	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
24	  });
25	  it("live cell with more than 3 neighbors dies (overpopulation) — center of filled 3x3 dies", () => {
26	    const filled: Cell[] = [
27	      [0, 0], [1, 0], [2, 0],
28	      [0, 1], [1, 1], [2, 1],
29	      [0, 2], [1, 2], [2, 2],
