31	    const result = nextGeneration(filled);
32	    expect(result).not.toEqual(expect.arrayContaining([[1, 1]]));
33	  });
34	  it("dead cell with exactly 3 neighbors becomes alive (reproduction) — L-shape produces new cell at (1,1)", () => {
35	    const lShape: Cell[] = [[0, 0], [1, 0], [0, 1]];
36	    const result = nextGeneration(lShape);
37	    expect(result).toEqual(expect.arrayContaining([[1, 1]]));
38	  });
39	  it("vertical blinker becomes horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
40	    const vertical: Cell[] = [[0, 0], [0, 1], [0, 2]];
41	    const result = nextGeneration(vertical);
42	    expect(result).toHaveLength(3);
43	    expect(result).toEqual(expect.arrayContaining([[-1, 1], [0, 1], [1, 1]] as Cell[]));
44	  });
45	  it("handles negative coordinates — block at negative coords stays unchanged", () => {
46	    const negBlock: Cell[] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
